    environment:
      - OFFLINE_MODE=true
      - MODEL_PATH=/models
    network_mode: none  # Complete network isolation

  ollama:
    image: ollama/ollama:latest
    volumes:
      - ./ollama-models:/root/.ollama
    network_mode: none

  agentdb:
    image: ruvector/agentdb:latest
    depends_on:
      - ruvector
      - ollama
    environment:
      - RUVECTOR_URL=http://ruvector:8080
      - OLLAMA_URL=http://ollama:11434
      - OFFLINE_MODE=true
    network_mode: none
```

