const { CausalModel } = require('agentdb/causal');

const agent = new AgentDB({
  causal: {
    enabled: true,
    inferenceMethod: 'do-calculus'
  }
});

// Define causal graph
const causalGraph = new CausalModel({
  variables: ['X', 'Y', 'Z', 'W'],
  edges: [
    { from: 'X', to: 'Y' },
    { from: 'Z', to: 'X' },
    { from: 'Z', to: 'Y' },
    { from: 'W', to: 'Y' }
  ],
  confounders: [
    { between: ['X', 'Y'], via: 'Z' }
  ]
});

agent.setCausalModel(causalGraph);
```

### Do-Calculus Operations

